sql:
SELECT COUNT(DISTINCT patient_id) AS 'Number of Patients with Low Blood Glucose level'
FROM glucose_readings
WHERE bg < 70;

SELECT patient_id, AVG(rate) AS avg_insulin_dose
FROM insulin_doses
GROUP BY patient_id;

SELECT patient_id FROM family_members
UNION ALL
SELECT patient_id FROM caregivers;

SELECT COUNT(DISTINCT patient_id) AS OngoingCriticalAlertsCount
FROM alerts
WHERE alert_type = 'Critical' AND resolved = 0;

SELECT patient_id, bg
FROM glucose_readings
WHERE bg <= 200;

SELECT first_name, last_name, dob, email, phone, gender, address, emergency_contact, medical_history, allergies, primary_care_provider_id
FROM patients
WHERE patient_id = (
    SELECT patient_id
    FROM readings_summary
    WHERE average_bg = (
        SELECT MAX(average_bg)
        FROM readings_summary
    )
);
